// TestOpenReadOnly_AgainstDeleteJournalDB pins the regression from the
// modernc DSN retrofit: OpenReadOnly must succeed on a pre-WAL (journal_mode
// = DELETE) database file. Earlier the DSN carried _pragma=journal_mode(WAL),
// which requires write access to perform the conversion and fails with
// SQLITE_READONLY on a mode=ro connection. Read-only commands (search,
// doctor) on pre-#877 databases would otherwise fail every invocation until
// the next sync.
func TestOpenReadOnly_AgainstDeleteJournalDB(t *testing.T) {
	t.Parallel()

	dbPath := filepath.Join(t.TempDir(), "tenderned.db")

	// Materialize a database file in DELETE journal mode, mirroring the
	// shape of a database created before the modernc DSN retrofit landed.
	writer, err := sql.Open("sqlite", "file:"+dbPath+"?_pragma=journal_mode(DELETE)")
	if err != nil {
		t.Fatalf("seeding writer: %v", err)
	}
	if _, err := writer.ExecContext(context.Background(), "CREATE TABLE smoke (id INTEGER PRIMARY KEY)"); err != nil {
		writer.Close()
		t.Fatalf("seeding table: %v", err)
	}
	var jm string
	if err := writer.QueryRowContext(context.Background(), "PRAGMA journal_mode").Scan(&jm); err != nil {
		writer.Close()
		t.Fatalf("reading journal_mode after seed: %v", err)
	}
	writer.Close()
	if jm != "delete" {
		t.Fatalf("test wiring: expected seeded DB to be in DELETE journal mode, got %q", jm)
	}

	store, err := OpenReadOnly(dbPath)
	if err != nil {
		t.Fatalf("OpenReadOnly against DELETE-journal DB: %v", err)
	}
	defer store.Close()

	// Exercise the connection — driver pragmas apply at first-use time, so
	// a failure to silently drop journal_mode(WAL) would surface here.
	if _, err := store.db.ExecContext(context.Background(), "SELECT COUNT(*) FROM smoke"); err != nil {
		t.Fatalf("read after OpenReadOnly on DELETE-journal DB: %v", err)
	}
}
